"use client";

import { useState, useEffect, useRef, useCallback } from "react";
import confetti from "canvas-confetti";
import { motion } from "framer-motion";

const QUESTIONS = [
  { q: "Who is IPL's all-time leading run-scorer?", opts: ["Rohit Sharma", "Virat Kohli", "Suresh Raina", "David Warner"], answer: 1 },
  { q: "Which team has won the most IPL titles?", opts: ["CSK", "MI", "KKR", "RCB"], answer: 1 },
  { q: "Who has the most IPL wickets all-time?", opts: ["Bumrah", "Malinga", "Yuzvendra Chahal", "Rashid Khan"], answer: 2 },
  { q: "What is the highest individual IPL score?", opts: ["158*", "175*", "167*", "172*"], answer: 1 },
  { q: "Who scored 175* in IPL 2013?", opts: ["AB de Villiers", "Chris Gayle", "Brendon McCullum", "David Warner"], answer: 1 },
  { q: "Which player won 3 Orange Caps?", opts: ["Kohli", "Rohit", "David Warner", "Buttler"], answer: 2 },
  { q: "What does the Impact Player rule allow?", opts: ["2 extra overs", "An extra substitute player", "DRS review", "Power play extension"], answer: 1 },
  { q: "How many centuries did Buttler score in IPL 2022?", opts: ["2", "3", "4", "5"], answer: 2 },
  { q: "Who captained KKR to back-to-back titles in 2012 and 2014?", opts: ["Dhoni", "Gambhir", "Dravid", "Sehwag"], answer: 1 },
  { q: "Which team did Hardik Pandya captain to their first IPL title?", opts: ["MI", "RCB", "GT", "SRH"], answer: 2 },
  { q: "Rashid Khan's IPL economy rate is approximately?", opts: ["7.8", "7.1", "6.8", "6.77"], answer: 3 },
  { q: "Which IPL season was played entirely in South Africa?", opts: ["2008", "2009", "2010", "2014"], answer: 1 },
  { q: "Who hit the first century in IPL history?", opts: ["Sehwag", "McCullum", "Gayle", "Hayden"], answer: 1 },
  { q: "How many runs did Kohli score in IPL 2016?", opts: ["723", "800", "873", "919"], answer: 2 },
  { q: "Which player is known as 'Mr. IPL'?", opts: ["Rohit Sharma", "MS Dhoni", "Suresh Raina", "Virat Kohli"], answer: 2 },
];

const OPTION_STYLES = [
  { bg: "#1A1AE6", text: "#FFFFFF", dark: false },
  { bg: "#9B5DE5", text: "#FFFFFF", dark: false },
  { bg: "#00C9A7", text: "#080C18", dark: true },
  { bg: "#FF9F1C", text: "#080C18", dark: true },
];

const TIERS = [
  { min: 130, label: "CRICKET GENIUS 🏆", color: "#F5C518" },
  { min: 90, label: "REAL FAN 🔥", color: "#E63946" },
  { min: 50, label: "CASUAL VIEWER 👀", color: "#00C9A7" },
  { min: 0, label: "JUST STARTED 🏏", color: "#FFFFFF" },
];

function shuffle<T>(arr: T[]): T[] {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

export function Trivia() {
  const [questions, setQuestions] = useState(QUESTIONS);
  const [currentQ, setCurrentQ] = useState(0);
  const [score, setScore] = useState(0);
  const [selected, setSelected] = useState<number | null>(null);
  const [timeLeft, setTimeLeft] = useState(15);
  const [gameOver, setGameOver] = useState(false);
  const timerRef = useRef<NodeJS.Timeout | null>(null);

  const question = questions[currentQ];

  const advance = useCallback(() => {
    if (currentQ >= questions.length - 1) {
      setGameOver(true);
    } else {
      setCurrentQ(prev => prev + 1);
      setSelected(null);
      setTimeLeft(15);
    }
  }, [currentQ, questions.length]);

  useEffect(() => {
    if (gameOver || selected !== null) return;
    timerRef.current = setInterval(() => {
      setTimeLeft(prev => {
        if (prev <= 1) {
          clearInterval(timerRef.current!);
          setTimeout(() => advance(), 500);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [currentQ, selected, gameOver, advance]);

  const handleSelect = (idx: number) => {
    if (selected !== null || gameOver) return;
    setSelected(idx);
    if (timerRef.current) clearInterval(timerRef.current);
    if (idx === question.answer) {
      setScore(prev => prev + 10);
      confetti({ particleCount: 80, spread: 60, origin: { y: 0.7 }, colors: ["#F5C518", "#1A1AE6", "#00C9A7", "#9B5DE5"], zIndex: 100 });
    }
    setTimeout(() => advance(), 1200);
  };

  const restart = () => {
    setQuestions(shuffle(QUESTIONS));
    setCurrentQ(0);
    setScore(0);
    setSelected(null);
    setTimeLeft(15);
    setGameOver(false);
  };

  const tier = TIERS.find(t => score >= t.min) || TIERS[TIERS.length - 1];

  if (gameOver) {
    return (
      <section className="py-24 md:py-32 w-full min-h-[90vh] flex items-center relative overflow-hidden" style={{ background: "#E63946" }}>
        <div className="max-w-[600px] mx-auto px-6 text-center z-10 relative">
          <motion.div initial={{ scale: 0 }} animate={{ scale: 1 }} transition={{ type: "spring", bounce: 0.5 }}>
            <h2 className="font-black uppercase leading-[0.85] text-white mb-4"
              style={{ fontFamily: "'Barlow Condensed', sans-serif", fontSize: "clamp(60px,12vw,100px)" }}>
              {score}<span style={{ color: "#F5C518" }}>/{questions.length * 10}</span>
            </h2>
            <p className="text-3xl font-black uppercase tracking-wider mb-2" style={{ fontFamily: "'Barlow Condensed', sans-serif", color: tier.color }}>
              {tier.label}
            </p>
            <p className="text-base mb-12" style={{ fontFamily: "Inter, sans-serif", color: "rgba(255,255,255,0.7)" }}>
              You got {score / 10} out of {questions.length} questions correct
            </p>
            <button onClick={restart}
              className="px-8 py-4 font-black text-lg uppercase tracking-widest rounded-md cursor-pointer hover:brightness-110 transition-all"
              style={{ background: "#F5C518", color: "#080C18", fontFamily: "'Barlow Condensed', sans-serif", border: "4px solid #080C18" }}>
              PLAY AGAIN
            </button>
          </motion.div>
        </div>
      </section>
    );
  }

  return (
    <section className="py-24 md:py-32 w-full min-h-[90vh] flex items-center relative overflow-hidden" style={{ background: "#E63946" }}>
      <div className="max-w-[1440px] mx-auto px-6 md:px-12 grid grid-cols-1 lg:grid-cols-2 gap-16 lg:gap-8 items-center w-full z-10 relative">

        {/* Left — Title */}
        <div className="flex flex-col items-start uppercase leading-[0.8] tracking-tighter" style={{ fontFamily: "'Barlow Condensed', sans-serif" }}>
          <motion.div initial={{ x: -100, opacity: 0 }} whileInView={{ x: 0, opacity: 1 }} transition={{ delay: 0.1, type: "spring", stiffness: 100 }}>
             <span className="text-white" style={{ fontSize: "clamp(100px, 14vw, 160px)", textShadow: "6px 6px 0 #080C18" }}>TEST</span>
          </motion.div>
          <motion.div initial={{ x: 100, opacity: 0 }} whileInView={{ x: 0, opacity: 1 }} transition={{ delay: 0.2, type: "spring", stiffness: 100 }}>
             <span style={{ fontSize: "clamp(100px, 14vw, 160px)", color: "#F5C518", textShadow: "6px 6px 0 #1A1AE6" }}>YOUR</span>
          </motion.div>
          <motion.div initial={{ x: -100, opacity: 0 }} whileInView={{ x: 0, opacity: 1 }} transition={{ delay: 0.3, type: "spring", stiffness: 100 }}>
             <span className="text-white" style={{ fontSize: "clamp(60px, 8vw, 100px)", textShadow: "6px 6px 0 #080C18" }}>CRICKET</span>
          </motion.div>
          <motion.div initial={{ y: 100, opacity: 0 }} whileInView={{ y: 0, opacity: 1 }} transition={{ delay: 0.4, type: "spring", stiffness: 100 }}>
             <span style={{ fontSize: "clamp(100px, 14vw, 160px)", color: "#F5C518", textShadow: "6px 6px 0 #1A1AE6" }}>
                 IQ<span style={{ color: "#9B5DE5" }}>.</span>
             </span>
          </motion.div>
        </div>

        {/* Right — Interactive Card */}
        <div className="flex justify-center lg:justify-end w-full">
           <div className="w-full max-w-[500px] rounded-lg p-8 pt-10 relative"
             style={{ background: "rgba(8,12,24,0.85)", backdropFilter: "blur(12px)", border: "2px solid rgba(245,197,24,0.25)" }}>

              {/* Header */}
              <div className="flex justify-between items-center mb-6">
                <span className="text-white text-xs font-bold uppercase tracking-widest" style={{ fontFamily: "Inter, sans-serif" }}>
                  Q{currentQ + 1} / {questions.length}
                </span>
                <div>
                  <span className="text-white text-sm font-bold mr-1" style={{ fontFamily: "Inter, sans-serif" }}>SCORE:</span>
                  <span className="text-lg font-black" style={{ fontFamily: "'Barlow Condensed', sans-serif", color: "#F5C518" }}>{score}</span>
                </div>
              </div>

              {/* Timer bar */}
              <div className="w-full h-1.5 rounded-full mb-6 overflow-hidden" style={{ background: "rgba(255,255,255,0.15)" }}>
                <motion.div className="h-full rounded-full"
                  style={{ background: "#F5C518" }}
                  key={currentQ}
                  initial={{ width: "100%" }}
                  animate={{ width: "0%" }}
                  transition={{ duration: 15, ease: "linear" }}
                />
              </div>

              {/* Question */}
              <h3 className="text-white font-bold text-xl leading-tight mb-8" style={{ fontFamily: "Inter, sans-serif" }}>
                {question.q}
              </h3>

              {/* Options — vivid colored cards */}
              <div className="space-y-3">
                {question.opts.map((opt, idx) => {
                  const style = OPTION_STYLES[idx];
                  let bg = style.bg;
                  let text = style.text;
                  let border = "transparent";
                  let badgeContent = String.fromCharCode(65 + idx);
                  let badgeBg = "#FFFFFF";
                  let badgeText = style.bg;
                  let scale = 1;

                  if (selected !== null) {
                    if (idx === question.answer) {
                      bg = "#00C9A7"; text = "#080C18"; border = "#F5C518";
                      badgeContent = "✓"; badgeBg = "#F5C518"; badgeText = "#080C18";
                    } else if (idx === selected) {
                      bg = "#E63946"; text = "#FFFFFF"; border = "#FFFFFF";
                      badgeContent = "✗"; badgeBg = "#FFFFFF"; badgeText = "#E63946";
                    } else {
                      bg = `${style.bg}55`; text = `${style.text}66`; border = "transparent";
                      badgeBg = `${style.text}33`; badgeText = `${style.text}66`;
                    }
                  }

                  return (
                    <motion.button
                      key={idx}
                      onClick={() => handleSelect(idx)}
                      disabled={selected !== null}
                      whileHover={selected === null ? { scale: 1.02, filter: "brightness(1.15)", borderColor: "#F5C518" } : {}}
                      className="w-full flex items-center p-4 rounded-lg font-bold text-base transition-all cursor-pointer disabled:cursor-default"
                      style={{
                        background: bg,
                        color: text,
                        borderBottomWidth: "3px",
                        borderTopWidth: "3px",
                        borderLeftWidth: "3px",
                        borderRightWidth: "3px",
                        borderStyle: "solid",
                        borderColor: border,
                        fontFamily: "Inter, sans-serif",
                        transform: `scale(${scale})`,
                      }}
                    >
                      <span className="font-black w-8 h-8 flex items-center justify-center mr-3 text-base shrink-0 rounded-md"
                        style={{ background: badgeBg, color: badgeText, fontFamily: "'Barlow Condensed', sans-serif", fontSize: "18px" }}>
                        {badgeContent}
                      </span>
                      <span className="text-left font-bold">{opt}</span>
                    </motion.button>
                  );
                })}
              </div>

              {/* Timer text */}
              <div className="mt-6 text-center">
                <span className="text-sm font-bold" style={{ fontFamily: "'JetBrains Mono', monospace", color: "rgba(255,255,255,0.5)" }}>
                  {timeLeft > 0 ? `${timeLeft}s remaining` : "Time's up!"}
                </span>
              </div>
           </div>
        </div>
      </div>
    </section>
  );
}

"use client";

import { useState, useEffect, useMemo, useRef } from "react";
import { Search } from "lucide-react";

interface MomentumMatch {
  matchId: string; date: string; teams: [string, string]; winner: string; venue: string;
  innings: { team: string; overs: number[]; total: number; wickets: number }[];
}

export function MomentumTrackerDemo() {
  const [matches, setMatches] = useState<MomentumMatch[]>([]);
  const [selectedIdx, setSelectedIdx] = useState(0);
  const [searchOpen, setSearchOpen] = useState(false);
  const [searchQuery, setSearchQuery] = useState("");
  const searchRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    fetch("/data/match-momentum.json")
      .then(r => r.json())
      .then(d => setMatches(d))
      .catch(() => {});
  }, []);

  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (searchRef.current && !searchRef.current.contains(e.target as Node)) setSearchOpen(false);
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const match = matches[selectedIdx];

  const filteredMatches = useMemo(() => {
    if (!searchQuery.trim()) return matches;
    const q = searchQuery.toLowerCase();
    return matches.filter(m =>
      m.teams[0].toLowerCase().includes(q) || m.teams[1].toLowerCase().includes(q) || m.date.includes(q)
    );
  }, [matches, searchQuery]);

  const maxOverRuns = useMemo(() => {
    if (!match) return 20;
    return Math.max(...match.innings.flatMap(i => i.overs), 20);
  }, [match]);

  return (
    <div className="p-6">
      {/* Match Search */}
      <div className="mb-6" ref={searchRef}>
        <label className="block text-xs font-bold uppercase tracking-widest mb-2" style={{ fontFamily: "Inter, sans-serif", color: "#F5C518" }}>SELECT MATCH</label>
        <div className="relative">
          <div className="flex items-center gap-2 rounded-lg px-3 py-3" style={{ background: "#080C18", border: "2px solid rgba(245,197,24,0.25)" }}>
            <Search size={16} color="#F5C518" className="shrink-0" />
            {!searchOpen && match ? (
              <button onClick={() => { setSearchOpen(true); setSearchQuery(""); }}
                className="w-full text-left text-sm font-bold text-white cursor-pointer bg-transparent border-none outline-none"
                style={{ fontFamily: "Inter, sans-serif" }}>
                {match.teams[0]} vs {match.teams[1]} — {match.date}
              </button>
            ) : (
              <input type="text" value={searchQuery}
                onChange={e => setSearchQuery(e.target.value)}
                onFocus={() => setSearchOpen(true)}
                placeholder="Search matches…"
                className="w-full bg-transparent border-none outline-none text-white text-sm font-bold placeholder:text-white/40"
                style={{ fontFamily: "Inter, sans-serif" }}
              />
            )}
          </div>
          {searchOpen && (
            <div className="absolute top-full left-0 w-full mt-1 rounded-lg overflow-hidden z-50 shadow-2xl"
              style={{ background: "#080C18", border: "1px solid rgba(245,197,24,0.35)", maxHeight: "280px", overflowY: "auto" }}>
              {filteredMatches.map((m, i) => {
                const realIdx = matches.indexOf(m);
                return (
                  <button key={m.matchId}
                    onClick={() => { setSelectedIdx(realIdx); setSearchOpen(false); setSearchQuery(""); }}
                    className="w-full text-left px-4 py-3 transition-colors cursor-pointer flex items-center gap-3"
                    style={{ background: realIdx === selectedIdx ? "rgba(245,197,24,0.08)" : "transparent", borderLeft: realIdx === selectedIdx ? "3px solid #F5C518" : "3px solid transparent" }}
                    onMouseEnter={e => (e.currentTarget.style.background = "rgba(245,197,24,0.08)")}
                    onMouseLeave={e => (e.currentTarget.style.background = realIdx === selectedIdx ? "rgba(245,197,24,0.08)" : "transparent")}
                  >
                    <span className="text-sm font-bold text-white flex-1" style={{ fontFamily: "Inter, sans-serif" }}>{m.teams[0]} vs {m.teams[1]}</span>
                    <span className="text-[11px] text-white/50" style={{ fontFamily: "'JetBrains Mono', monospace" }}>{m.date}</span>
                  </button>
                );
              })}
              {filteredMatches.length === 0 && (
                <div className="p-4 text-center text-sm" style={{ fontFamily: "Inter, sans-serif", color: "rgba(255,255,255,0.4)" }}>No matches found</div>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Match Info */}
      {match && (
        <>
          <div className="flex justify-between items-center mb-4">
            <span className="text-white text-sm font-bold" style={{ fontFamily: "Inter, sans-serif" }}>
              {match.teams[0]} vs {match.teams[1]}
            </span>
            <span className="text-xs font-bold px-2 py-1 rounded-sm" style={{ background: "#F5C518", color: "#080C18", fontFamily: "'Barlow Condensed', sans-serif" }}>
              {match.winner === match.teams[0] || match.winner === match.teams[1] ? `${match.winner} won` : "TIE"}
            </span>
          </div>

          {/* Score Summary */}
          <div className="grid grid-cols-2 gap-3 mb-6">
            {match.innings.map((inn, i) => (
              <div key={i} className="p-3 rounded-lg text-center" style={{ background: i === 0 ? "#1A1AE6" : "#9B5DE5" }}>
                <span className="block text-[10px] font-bold uppercase tracking-widest text-white mb-1" style={{ fontFamily: "Inter, sans-serif" }}>{inn.team}</span>
                <span className="block text-2xl font-black" style={{ fontFamily: "'JetBrains Mono', monospace", color: "#F5C518" }}>
                  {inn.total}/{inn.wickets}
                </span>
                <span className="block text-[10px] text-white/60" style={{ fontFamily: "Inter, sans-serif" }}>({inn.overs.length} overs)</span>
              </div>
            ))}
          </div>

          {/* Over-by-over Bars */}
          <h4 className="text-xs font-bold uppercase tracking-widest text-white mb-3" style={{ fontFamily: "Inter, sans-serif" }}>OVER-BY-OVER</h4>
          <div className="space-y-1 max-h-[300px] overflow-y-auto pr-2" style={{ scrollbarColor: "#F5C518 transparent" }}>
            {Array.from({ length: Math.max(...match.innings.map(i => i.overs.length)) }).map((_, overIdx) => (
              <div key={overIdx} className="flex items-center gap-2">
                <span className="text-[10px] font-bold w-6 shrink-0 text-right" style={{ fontFamily: "'JetBrains Mono', monospace", color: "rgba(255,255,255,0.5)" }}>{overIdx + 1}</span>
                <div className="flex-1 flex gap-1">
                  {match.innings.map((inn, innIdx) => {
                    const runs = inn.overs[overIdx] ?? 0;
                    const pct = (runs / maxOverRuns) * 100;
                    return (
                      <div key={innIdx} className="flex-1 h-5 rounded-sm relative overflow-hidden" style={{ background: "rgba(255,255,255,0.08)" }}>
                        <div className="h-full rounded-sm transition-all duration-300" style={{ width: `${pct}%`, background: innIdx === 0 ? "#1A1AE6" : "#9B5DE5" }} />
                        <span className="absolute inset-0 flex items-center justify-center text-[9px] font-black text-white" style={{ fontFamily: "'JetBrains Mono', monospace" }}>{runs}</span>
                      </div>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>

          {/* Legend */}
          <div className="flex justify-center gap-6 mt-4">
            {match.innings.map((inn, i) => (
              <div key={i} className="flex items-center gap-2">
                <div className="w-3 h-3 rounded-sm" style={{ background: i === 0 ? "#1A1AE6" : "#9B5DE5" }} />
                <span className="text-xs font-bold text-white" style={{ fontFamily: "Inter, sans-serif" }}>{inn.team}</span>
              </div>
            ))}
          </div>
        </>
      )}

      {!matches.length && <p className="text-center py-8 text-sm" style={{ fontFamily: "Inter, sans-serif", color: "rgba(255,255,255,0.4)" }}>Loading match data…</p>}
    </div>
  );
}
